SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1, CITY1_final AS CITY1, CITY2_final AS CITY2, EMAIL
FROM J09D_joined
WHERE ENTSCHEIDUNG = 'MANDATORY_READING';

SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1, CITY1_final AS CITY1, CITY2_final AS CITY2, EMAIL
FROM J09D_joined
WHERE ENTSCHEIDUNG = 'DIRECT_MAIL';

SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1, CITY1_final AS CITY1, CITY2_final AS CITY2, EMAIL
FROM J09D_joined
WHERE ENTSCHEIDUNG NOT IN ('MANDATORY_READING', 'DIRECT_MAIL');
